import React, { useEffect, useState } from "react";

export default function FriendsList({ currentUser, onSelectFriend }) {
  const [friends, setFriends] = useState([]);
  const [newFriend, setNewFriend] = useState("");

  useEffect(() => {
    fetch(`http://localhost:3001/friends/${currentUser.userId}`)
      .then(res => res.json())
      .then(data => setFriends(data));
  }, [currentUser.userId]);

  const addFriend = () => {
    if (!newFriend.trim()) return;
    fetch("http://localhost:3001/addFriend", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ userId: currentUser.userId, friendId: newFriend })
    })
      .then(res => res.json())
      .then(() => {
        setFriends(prev => [...prev, newFriend]);
        setNewFriend("");
      });
  };

  return (
    <div style={styles.container}>
      <h2>Your Friends</h2>
      {friends.map((f, i) => (
        <button key={i} style={styles.friendBtn} onClick={() => onSelectFriend({ userId: f })}>
          {f}
        </button>
      ))}
      <div style={styles.addBox}>
        <input
          style={styles.input}
          value={newFriend}
          onChange={(e) => setNewFriend(e.target.value)}
          placeholder="Add friend by ID"
        />
        <button style={styles.addBtn} onClick={addFriend}>Add</button>
      </div>
    </div>
  );
}

const styles = {
  container: { maxWidth: 300, margin: "20px auto", textAlign: "center" },
  friendBtn: {
    display: "block", width: "100%", padding: 10, margin: "5px 0",
    borderRadius: 5, border: "1px solid #ccc",
    backgroundColor: "#25D366", color: "white", cursor: "pointer"
  },
  addBox: { marginTop: 15, display: "flex" },
  input: { flex: 1, padding: 8, borderRadius: 5, border: "1px solid #ccc" },
  addBtn: {
    marginLeft: 5, padding: "8px 15px", borderRadius: 5,
    border: "none", backgroundColor: "#075E54", color: "white", cursor: "pointer"
  }
};
